// Node 2: Parse & Validasi Context dari /api/ai/context
// Struktur response:
// { status: true, data: { device, sensor, weather_current, weather_forecast,
//                         batch, knowledge, pending_decisions, ai_summary } }

const response = $input.first().json;

if (!response.status || !response.data) {
  throw new Error('Context API gagal: ' + JSON.stringify(response));
}

const data     = response.data;
const sensor   = data.sensor;
const batch    = data.batch;
const device   = data.device;
const aiSummary = data.ai_summary;

// Tidak ada batch aktif (status drying/paused) â†’ skip cycle ini
if (!batch) {
  return [{
    json: {
      skip: true,
      reason: 'Tidak ada batch aktif (status drying/paused)',
      timestamp: new Date().toISOString()
    }
  }];
}

// Tidak ada data sensor valid â†’ skip
if (!sensor) {
  return [{
    json: {
      skip: true,
      reason: 'Tidak ada data sensor valid untuk device ini',
      timestamp: new Date().toISOString()
    }
  }];
}

// Sensor stale > 30 menit â†’ skip (kemungkinan device offline)
const recordedAt = sensor.recorded_at ? new Date(sensor.recorded_at) : null;
const ageMinutes = recordedAt ? (Date.now() - recordedAt.getTime()) / 60000 : 99;
if (ageMinutes > 30) {
  return [{
    json: {
      skip: true,
      reason: `Sensor stale ${Math.round(ageMinutes)} menit â€” kemungkinan device offline`,
      timestamp: new Date().toISOString()
    }
  }];
}

// Flatten sensor: nilai numerik dari Eloquent bisa jadi string, paksa float
const s = {
  temperature_inside:  parseFloat(sensor.temperature_inside  ?? 0),
  temperature_outside: parseFloat(sensor.temperature_outside ?? 0),
  humidity_inside:     parseFloat(sensor.humidity_inside     ?? 0),
  humidity_outside:    parseFloat(sensor.humidity_outside    ?? 0),
  solar_irradiance:    parseFloat(sensor.solar_irradiance    ?? 0),
  grain_moisture:      parseFloat(sensor.grain_moisture      ?? 20),
  grain_weight:        parseFloat(sensor.grain_weight        ?? 0),
  wind_speed:          parseFloat(sensor.wind_speed          ?? 0),
  pid_setpoint:        sensor.pid_setpoint != null ? parseFloat(sensor.pid_setpoint) : null,
  pid_output:          sensor.pid_output   != null ? parseFloat(sensor.pid_output)   : null,
  ai_active:           sensor.ai_active    ?? false,
  recorded_at:         sensor.recorded_at
};

// Flatten batch
const b = {
  id:               batch.id,
  batch_code:       batch.batch_code,
  rice_type:        batch.rice_type,
  rice_variety:     batch.rice_variety,
  initial_weight:   parseFloat(batch.initial_weight   ?? 0),
  current_weight:   parseFloat(batch.current_weight   ?? batch.initial_weight ?? 0),
  initial_moisture: parseFloat(batch.initial_moisture ?? 20),
  current_moisture: parseFloat(batch.current_moisture ?? batch.initial_moisture ?? 20),
  target_moisture:  parseFloat(batch.target_moisture  ?? 14),
  drying_method:    batch.drying_method ?? 'Hybrid',
  operator_name:    batch.operator_name,
  petani_name:      batch.petani_name,
  petani_phone:     batch.petani_phone,
  status:           batch.status,
  start_time:       batch.start_time
};

return [{
  json: {
    skip:             false,
    device_id:        device?.id ?? 1,
    batch_id:         b.id,
    sensor:           s,
    batch:            b,
    weather_current:  data.weather_current  ?? null,
    weather_forecast: data.weather_forecast ?? null,
    ai_summary:       aiSummary ?? {},
    knowledge:        data.knowledge ?? {},
    // Flag ringkas untuk dipakai agent
    is_rain_risk_high: (aiSummary?.rain_risk_6h === 'high'),
    is_temp_critical:  (s.temperature_inside > 57 || s.temperature_inside < 35),
    is_humidity_high:  (s.humidity_inside > 70),
    is_grain_dry:      (s.grain_moisture < 14),
    alerts:            aiSummary?.alerts ?? []
  }
}];

// WEATHER AGENT â€” analisis cuaca aktual + forecast OpenWeather
// Source: data.weather_current (OpenWeather API via OpenWeatherService)
//         data.weather_forecast (forecastSummaryForAi)
// Tugas: tentukan apakah aman untuk pengeringan dan rekomendasi aksi cuaca

const ctx      = $input.first().json;
const weather  = ctx.weather_current  ?? {};
const forecast = ctx.weather_forecast ?? {};

// Nilai default aman jika API cuaca tidak tersedia
const rainfall  = parseFloat(weather.rainfall_1h  ?? 0);
const clouds    = parseFloat(weather.clouds       ?? 0);
const solarIrr  = parseFloat(ctx.sensor?.solar_irradiance ?? 0);
const available = forecast.available ?? false;

let weatherAgent = {
  safe_to_dry:     true,
  reason:          'Cuaca kondusif untuk pengeringan',
  recommendation:  null,
  urgency:         'low',
  solar_available: solarIrr > 200
};

// Prioritas 1: Hujan aktual (sensor di luar atau OpenWeather)
if (rainfall > 0.5) {
  weatherAgent = {
    safe_to_dry:     false,
    reason:          `Hujan aktual ${rainfall.toFixed(1)} mm/jam terdeteksi`,
    recommendation:  'pause_drying',
    urgency:         'critical',
    solar_available: false
  };
}
// Prioritas 2: Forecast hujan tinggi dalam 6 jam
else if (available && forecast.rain_risk_6h === 'high') {
  weatherAgent = {
    safe_to_dry:     false,
    reason:          `Risiko hujan tinggi 6 jam ke depan (prob: ${forecast.max_pop_6h ?? '?'})`,
    recommendation:  'prepare_close',
    urgency:         'high',
    solar_available: solarIrr > 200
  };
}
// Prioritas 3: Forecast hujan sedang dalam 6 jam
else if (available && forecast.rain_risk_6h === 'medium') {
  weatherAgent = {
    safe_to_dry:     true,
    reason:          `Kemungkinan hujan sedang 6 jam ke depan (prob: ${forecast.max_pop_6h ?? '?'}) â€” pantau`,
    recommendation:  'monitor',
    urgency:         'medium',
    solar_available: solarIrr > 200
  };
}
// Prioritas 4: Mendung tebal, surya rendah
else if (clouds > 80 || solarIrr < 100) {
  weatherAgent = {
    safe_to_dry:     true,
    reason:          `Awan tebal ${clouds}%, iradiasi surya ${solarIrr} W/mÂ² â€” heater listrik diperlukan`,
    recommendation:  'use_heater',
    urgency:         'low',
    solar_available: false
  };
}
// Prioritas 5: Cuaca cerah, surya optimal
else if (clouds < 30 && solarIrr > 400) {
  weatherAgent = {
    safe_to_dry:     true,
    reason:          `Cuaca cerah, iradiasi surya ${solarIrr} W/mÂ² â€” energi surya optimal`,
    recommendation:  'optimize_solar',
    urgency:         'low',
    solar_available: true
  };
}

// Sertakan jendela hujan pertama jika ada
if (available && forecast.next_rain_window) {
  weatherAgent.next_rain_window = forecast.next_rain_window;
}

return [{ json: { ...ctx, weather_agent: weatherAgent } }];

// DRYER AGENT â€” analisis kondisi fisik alat pengering
// Arsitektur LLM+PID:
//   AI tidak kontrol relay heater langsung
//   AI tentukan target_temperature â†’ PID ESP32 yang capai setpoint itu
// Tugas: rekomendasikan setpoint suhu + konfigurasi fan berdasarkan sensor

const ctx    = $input.first().json;
const sensor = ctx.sensor;
const batch  = ctx.batch;

const tempIn   = sensor.temperature_inside;
const humIn    = sensor.humidity_inside;
const solarIrr = sensor.solar_irradiance;

// Koreksi setpoint berdasarkan iradiasi surya (hemat energi hibrida)
// Surya dominan â†’ heater bisa dikurangi karena panas alami sudah membantu
let solarBonus;
let solarMode;
if (solarIrr > 600) {
  solarBonus = -3;
  solarMode  = 'surya dominan';
} else if (solarIrr > 200) {
  solarBonus = -1;
  solarMode  = 'hybrid';
} else {
  solarBonus = 0;
  solarMode  = 'listrik dominan';
}

// PID setpoint aktif di ESP32 (jika ada)
const currentSetpoint = sensor.pid_setpoint ?? null;
const aiActive        = sensor.ai_active    ?? false;

let dryerAgent = {
  target_temp:   45,
  fan_needed:    true,
  fan_speed:     70,
  fan_mode:      'auto',
  solar_mode:    solarMode,
  solar_irr:     solarIrr,
  current_setpoint: currentSetpoint,
  ai_active_esp32:  aiActive,
  reason:        '',
  urgency:       'low'
};

// KRITIS: suhu terlalu tinggi â€” risiko gabah gosong
if (tempIn > 57) {
  dryerAgent = {
    target_temp:   35,   // setpoint rendah â†’ PID matikan heater
    fan_needed:    true,
    fan_speed:     100,
    fan_mode:      'forced_on',
    solar_mode:    solarMode,
    solar_irr:     solarIrr,
    current_setpoint: currentSetpoint,
    ai_active_esp32:  aiActive,
    reason:        `KRITIS: Suhu ${tempIn}Â°C melebihi batas aman 57Â°C â€” setpoint diturunkan ke 35Â°C`,
    urgency:       'critical'
  };
}
// Suhu terlalu rendah â€” pengeringan tidak efektif
else if (tempIn < 38) {
  const target = Math.max(40, 47 + solarBonus);
  dryerAgent = {
    target_temp:   target,
    fan_needed:    true,
    fan_speed:     60,
    fan_mode:      'auto',
    solar_mode:    solarMode,
    solar_irr:     solarIrr,
    current_setpoint: currentSetpoint,
    ai_active_esp32:  aiActive,
    reason:        `Suhu ${tempIn}Â°C < 38Â°C, naikkan setpoint ke ${target}Â°C. Surya: ${solarIrr} W/mÂ² (${solarMode})`,
    urgency:       'high'
  };
}
// RH tinggi â€” butuh sirkulasi ekstra
else if (humIn > 75) {
  const target = Math.max(40, 46 + solarBonus);
  dryerAgent = {
    target_temp:   target,
    fan_needed:    true,
    fan_speed:     90,
    fan_mode:      'forced_on',
    solar_mode:    solarMode,
    solar_irr:     solarIrr,
    current_setpoint: currentSetpoint,
    ai_active_esp32:  aiActive,
    reason:        `RH ${humIn}% sangat tinggi, fan forced ON. Surya: ${solarIrr} W/mÂ² (${solarMode})`,
    urgency:       'medium'
  };
}
// Kondisi normal
else {
  // Jika surya cukup, heater listrik bisa dikurangi (efisiensi energi)
  const heaterSave = solarIrr > 400;
  const target = Math.max(40, 45 + solarBonus);
  dryerAgent = {
    target_temp:   target,
    fan_needed:    true,
    fan_speed:     humIn > 65 ? 80 : 70,
    fan_mode:      humIn > 65 ? 'forced_on' : 'auto',
    solar_mode:    solarMode,
    solar_irr:     solarIrr,
    current_setpoint: currentSetpoint,
    ai_active_esp32:  aiActive,
    reason:        `Kondisi normal: suhu ${tempIn}Â°C, RH ${humIn}%, setpoint ${target}Â°C. Surya: ${solarIrr} W/mÂ² (${solarMode})${heaterSave ? ' â€” heater hemat energi' : ''}`,
    urgency:       'low'
  };
}

return [{ json: { ...ctx, dryer_agent: dryerAgent } }];

// QUALITY AGENT â€” analisis kualitas gabah dan estimasi selesai
// Input: sensor.grain_moisture (kadar air gabah real-time dari loadcell+kapasitif)
//        batch.current_moisture, batch.target_moisture
// Tugas: deteksi risiko (bertunas, gosong), estimasi jam tersisa, rekomendasi stop

const ctx    = $input.first().json;
const sensor = ctx.sensor;
const batch  = ctx.batch;

const grainMoisture  = sensor.grain_moisture;
const tempIn         = sensor.temperature_inside;
const humIn          = sensor.humidity_inside;
const targetMoisture = batch.target_moisture;

// Gunakan grain_moisture dari sensor sebagai sumber kebenaran utama
// fallback ke batch.current_moisture jika sensor tidak baca kadar air
const effectiveMoisture = grainMoisture > 0 ? grainMoisture : (batch.current_moisture ?? batch.initial_moisture);

let qualityAgent = {
  risk_level:               'low',
  risk_sprouting:           false,
  risk_burnt:               false,
  grain_dry:                false,
  effective_moisture:       effectiveMoisture,
  recommendation:           null,
  estimated_hours_remaining: null,
  reason:                   ''
};

// Prioritas 1: Kadar air sudah mencapai target â†’ selesai
if (effectiveMoisture <= targetMoisture) {
  qualityAgent = {
    risk_level:               'low',
    risk_sprouting:           false,
    risk_burnt:               false,
    grain_dry:                true,
    effective_moisture:       effectiveMoisture,
    recommendation:           'stop_heater',
    estimated_hours_remaining: 0,
    reason:                   `Kadar air ${effectiveMoisture}% sudah mencapai target ${targetMoisture}% â€” pengeringan selesai`
  };
}
// Prioritas 2: KRITIS â€” risiko bertunas (RH+suhu kombinasi buruk)
else if (humIn > 80 && tempIn < 40) {
  qualityAgent = {
    risk_level:               'critical',
    risk_sprouting:           true,
    risk_burnt:               false,
    grain_dry:                false,
    effective_moisture:       effectiveMoisture,
    recommendation:           'alert_operator',
    estimated_hours_remaining: null,
    reason:                   `KRITIS: RH ${humIn}% + suhu ${tempIn}Â°C â€” kondisi ideal untuk gabah bertunas (sprouting)`
  };
}
// Prioritas 3: KRITIS â€” risiko gabah gosong
else if (tempIn > 60) {
  qualityAgent = {
    risk_level:               'critical',
    risk_sprouting:           false,
    risk_burnt:               true,
    grain_dry:                false,
    effective_moisture:       effectiveMoisture,
    recommendation:           'stop_heater',
    estimated_hours_remaining: null,
    reason:                   `KRITIS: Suhu ${tempIn}Â°C melebihi 60Â°C â€” risiko kerusakan pati gabah`
  };
}
// Kondisi normal â€” hitung estimasi
else {
  // Laju pengeringan kasar berdasarkan suhu
  // Referensi: SNI 01-0224-1987 kadar air gabah 14%
  let dryingRate;
  if (tempIn >= 50)      dryingRate = 1.4;  // Â°C/jam (pengeringan intensif)
  else if (tempIn >= 45) dryingRate = 1.0;  // normal
  else if (tempIn >= 40) dryingRate = 0.7;  // ringan
  else                   dryingRate = 0.4;  // kurang optimal

  const moistureGap    = Math.max(0, effectiveMoisture - targetMoisture);
  const hoursRemaining = moistureGap > 0 ? moistureGap / dryingRate : 0;

  qualityAgent = {
    risk_level:               humIn > 70 ? 'medium' : 'low',
    risk_sprouting:           humIn > 75 && tempIn < 42,
    risk_burnt:               false,
    grain_dry:                false,
    effective_moisture:       effectiveMoisture,
    recommendation:           null,
    estimated_hours_remaining: Math.round(hoursRemaining * 10) / 10,
    reason:                   `Kadar air ${effectiveMoisture}% â†’ target ${targetMoisture}%, estimasi ${Math.round(hoursRemaining * 10) / 10} jam (laju ${dryingRate}%/jam pada ${tempIn}Â°C)`
  };
}

return [{ json: { ...ctx, quality_agent: qualityAgent } }];

// AI COORDINATOR â€” LLM+PID Hybrid Architecture (v4)
// Menggabungkan output ketiga agent â†’ keputusan final
// AI tentukan setpoint suhu optimal â†’ PID ESP32 yang eksekusi via relay heater
// Notifikasi sudah ditangani di AIAgentController.decide() â†’ coordinator hanya set flag

const ctx          = $input.first().json;
const weatherAgent = ctx.weather_agent;
const dryerAgent   = ctx.dryer_agent;
const qualityAgent = ctx.quality_agent;
const sensor       = ctx.sensor;
const batch        = ctx.batch;

// Helper: clamp setpoint ke range aman 35â€“55Â°C
const clamp = (v, min = 35, max = 55) => Math.max(min, Math.min(max, v ?? 45));

let finalDecision;

// â”€â”€ PRIORITAS 1: Gabah sudah kering â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
if (qualityAgent.grain_dry) {
  finalDecision = {
    decision_type:    'stop_heater',
    reasoning:        qualityAgent.reason.substring(0, 200),
    confidence_score: 0.99,
    output_action: {
      target_temperature: 35,   // PID tidak nyalakan heater
      fan:        false,
      fan_speed:  0,
      duration_hours: 0,
      mode:       'auto',
      risk_level: 'low',
      alerts:     ['Gabah selesai! Kadar air mencapai target ' + batch.target_moisture + '%. Silakan ambil.']
    }
  };
}
// â”€â”€ PRIORITAS 2: Kondisi kritis gabah (bertunas/gosong) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
else if (qualityAgent.risk_level === 'critical') {
  finalDecision = {
    decision_type:    qualityAgent.recommendation ?? 'alert_operator',
    reasoning:        qualityAgent.reason.substring(0, 200),
    confidence_score: 0.97,
    output_action: {
      target_temperature: 35,
      fan:        true,
      fan_speed:  100,
      duration_hours: 0,
      mode:       'forced_on',
      risk_level: 'critical',
      alerts:     [qualityAgent.reason]
    }
  };
}
// â”€â”€ PRIORITAS 3: Hujan aktual â†’ pause_drying â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
else if (!weatherAgent.safe_to_dry && weatherAgent.urgency === 'critical') {
  finalDecision = {
    decision_type:    'pause_drying',
    reasoning:        weatherAgent.reason.substring(0, 200),
    confidence_score: 0.95,
    output_action: {
      target_temperature: 35,
      fan:        false,
      fan_speed:  0,
      duration_hours: 0,
      mode:       'auto',
      risk_level: 'high',
      alerts:     [weatherAgent.reason]
    }
  };
}
// â”€â”€ PRIORITAS 4: Suhu dryer kritis â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
else if (dryerAgent.urgency === 'critical') {
  finalDecision = {
    decision_type:    'stop_heater',
    reasoning:        dryerAgent.reason.substring(0, 200),
    confidence_score: 0.97,
    output_action: {
      target_temperature: 35,
      fan:        true,
      fan_speed:  100,
      duration_hours: 1,
      mode:       'forced_on',
      risk_level: 'critical',
      alerts:     [dryerAgent.reason]
    }
  };
}
// â”€â”€ PRIORITAS 5: Forecast hujan tinggi â†’ kurangi setpoint, siap-siap pause â”€â”€â”€
else if (!weatherAgent.safe_to_dry && weatherAgent.urgency === 'high') {
  const safeTarget = clamp(dryerAgent.target_temp - 4);
  finalDecision = {
    decision_type:    'adjust_temperature',
    reasoning:        (weatherAgent.reason + ' | Setpoint diturunkan preventif').substring(0, 200),
    confidence_score: 0.85,
    output_action: {
      target_temperature: safeTarget,
      fan:        dryerAgent.fan_needed,
      fan_speed:  dryerAgent.fan_speed,
      duration_hours: 1,
      mode:       'auto',
      risk_level: 'medium',
      alerts:     [weatherAgent.reason]
    }
  };
}
// â”€â”€ PRIORITAS 6: Kondisi normal â€” setpoint optimal berdasarkan kadar air â”€â”€â”€â”€â”€â”€
else {
  const moisture   = qualityAgent.effective_moisture;
  let baseSetpoint;
  if      (moisture > 25) baseSetpoint = 52;  // pengeringan intensif
  else if (moisture > 20) baseSetpoint = 49;  // normal atas
  else if (moisture > 18) baseSetpoint = 47;  // normal
  else if (moisture > 16) baseSetpoint = 45;  // menjelang akhir
  else if (moisture > 14) baseSetpoint = 43;  // akhir, hati-hati
  else                    baseSetpoint = 35;  // sudah kering

  // Kurangi setpoint jika cuaca warning (hemat energi + preventif)
  if (weatherAgent.urgency === 'medium') baseSetpoint -= 2;
  // Kurangi jika RH tinggi
  if (sensor.humidity_inside > 70) baseSetpoint -= 2;

  const targetTemp = clamp(baseSetpoint);
  const fanMode    = sensor.humidity_inside > 70 ? 'forced_on' : 'auto';
  const duration   = qualityAgent.estimated_hours_remaining ?? 2;

  const reasonParts = [
    weatherAgent.reason,
    dryerAgent.reason,
    qualityAgent.reason
  ].filter(Boolean);
  const reasoning = reasonParts.join(' | ').substring(0, 200);

  finalDecision = {
    decision_type:    moisture <= 14 ? 'stop_heater' : 'adjust_temperature',
    reasoning:        reasoning,
    confidence_score: weatherAgent.urgency === 'medium' ? 0.78 : 0.85,
    output_action: {
      target_temperature: targetTemp,
      fan:           dryerAgent.fan_needed,
      fan_speed:     dryerAgent.fan_speed,
      duration_hours: duration,
      mode:          fanMode,
      risk_level:    qualityAgent.risk_level,
      alerts:        ctx.alerts ?? []
    }
  };
}

// Payload untuk POST /api/ai/decide
const decidePayload = {
  device_id:        ctx.device_id,
  batch_id:         ctx.batch_id,
  decision_type:    finalDecision.decision_type,
  reasoning:        finalDecision.reasoning,
  confidence_score: finalDecision.confidence_score,
  ai_model:         'n8n-multiagent-pid-v4',
  input_data: {
    sensor: {
      temperature_inside:  sensor.temperature_inside,
      humidity_inside:     sensor.humidity_inside,
      solar_irradiance:    sensor.solar_irradiance,
      grain_moisture:      sensor.grain_moisture,
      pid_setpoint:        sensor.pid_setpoint,
      ai_active:           sensor.ai_active
    },
    weather_current: ctx.weather_current
      ? {
          temperature:  ctx.weather_current.temperature,
          humidity:     ctx.weather_current.humidity,
          clouds:       ctx.weather_current.clouds,
          rainfall_1h:  ctx.weather_current.rainfall_1h,
          description:  ctx.weather_current.description
        }
      : null,
    weather_forecast: ctx.weather_forecast
      ? {
          rain_risk_6h:    ctx.weather_forecast.rain_risk_6h,
          rain_risk_24h:   ctx.weather_forecast.rain_risk_24h,
          max_pop_6h:      ctx.weather_forecast.max_pop_6h,
          next_rain_window: ctx.weather_forecast.next_rain_window
        }
      : null,
    agents: {
      weather: weatherAgent,
      dryer:   dryerAgent,
      quality: qualityAgent
    }
  },
  output_action: finalDecision.output_action
};

console.log('[Coordinator v4]',
  finalDecision.decision_type,
  '| setpoint:', finalDecision.output_action.target_temperature + 'Â°C',
  '| confidence:', finalDecision.confidence_score,
  '| risk:', finalDecision.output_action.risk_level
);

return [{
  json: {
    ...ctx,
    final_decision: finalDecision,
    decide_payload: decidePayload
  }
}];

// SAVE CONTEXT NODE â€” simpan ctx lengkap SEBELUM HTTP Request
// Bug fix: setelah node HTTP Request, $json berisi response API bukan ctx
// Solusi: simpan final_decision + payload di node ini,
//         lalu node downstream ambil via $('Save Context').first().json

const ctx = $input.first().json;

// Teruskan semua data ctx + metadata pengiriman
return [{
  json: {
    device_id:      ctx.device_id,
    batch_id:       ctx.batch_id,
    final_decision: ctx.final_decision,
    decide_payload: ctx.decide_payload,
    sensor:         ctx.sensor,
    batch:          ctx.batch,
    weather_agent:  ctx.weather_agent,
    dryer_agent:    ctx.dryer_agent,
    quality_agent:  ctx.quality_agent,
    alerts:         ctx.alerts ?? []
  }
}];

// NOTIFICATION AGENT â€” tentukan apakah perlu notifikasi tambahan ke n8n
// Catatan: notifikasi utama (pause, resume, critical, completed) sudah ditangani
// secara otomatis di AIAgentController.decide() di Laravel
// Node ini hanya sebagai safety net untuk alert yang belum ter-cover Laravel

// Ambil ctx dari Save Context (bukan dari response HTTP post-decision)
const ctx      = $('7. Save Context').first().json;
const decision = ctx.final_decision;
const alerts   = decision.output_action?.alerts ?? [];
const riskLevel = decision.output_action?.risk_level ?? 'low';

// Hanya kirim notifikasi via n8n jika:
// 1. Risk critical DAN ada pesan alert, ATAU
// 2. Risk high DAN ada pesan alert
// (medium/low sudah diurus Laravel)
const shouldNotify = (
  (riskLevel === 'critical' || riskLevel === 'high') &&
  alerts.length > 0
);

if (!shouldNotify) {
  return [{
    json: {
      skip_notification: true,
      final_decision:    decision,
      device_id:         ctx.device_id,
      batch_id:          ctx.batch_id
    }
  }];
}

// Payload ke POST /api/iot/notification
const notifPayload = {
  device_id: ctx.device_id,
  batch_id:  ctx.batch_id ?? null,
  type:      riskLevel === 'critical' ? 'alert' : 'warning',
  category:  decision.decision_type === 'pause_drying'
               ? 'weather_alert'
               : (riskLevel === 'critical' ? 'temperature_alert' : 'ai_decision'),
  title:     riskLevel === 'critical'
               ? 'ðŸš¨ Kondisi Kritis â€” Perlu Tindakan Segera'
               : 'âš ï¸ Perhatian Diperlukan',
  message:   alerts.join(' | ') || decision.reasoning,
  data: {
    decision_type: decision.decision_type,
    risk_level:    riskLevel,
    target_temp:   decision.output_action?.target_temperature,
    fan_mode:      decision.output_action?.mode
  },
  is_read:   false
};

return [{
  json: {
    skip_notification: false,
    notif_payload:     notifPayload,
    final_decision:    decision,
    device_id:         ctx.device_id,
    batch_id:          ctx.batch_id
  }
}];

// SKIP DONE â€” alur ketika tidak ada batch/sensor aktif
// Di-reach dari output false Ada Batch & Sensor? (index 1)
const ctx = $input.first().json;
console.log('[SolarDryerAI] Cycle di-skip:', ctx.reason ?? 'unknown', ctx.timestamp ?? '');
return [{ json: { status: 'skipped', reason: ctx.reason, timestamp: ctx.timestamp } }];

// DONE â€” log akhir cycle
// Di-reach dari: post-notification (setelah kirim notif) atau check-notification false branch
const ctx = $input.first().json;
const decision = ctx.final_decision ?? {};
console.log('[SolarDryerAI] Cycle selesai:', {
  decision_type:    decision.decision_type,
  target_temp:      decision.output_action?.target_temperature,
  risk_level:       decision.output_action?.risk_level,
  confidence:       decision.confidence_score,
  timestamp:        new Date().toISOString()
});
return [{
  json: {
    status:        'done',
    decision_type: decision.decision_type,
    target_temp:   decision.output_action?.target_temperature,
    risk_level:    decision.output_action?.risk_level,
    timestamp:     new Date().toISOString()
  }
}];
